const DEPTH: u16 = 10;
const EDGES: u16 = 18;
const SCALING_FACTOR: f64 = 360.0 / EDGES as f64 / 2.0;

fn get_angles(edges: u16) -> Vec<u16> {
    // Divide the circle into a vector of angles
    (0..edges).map(|i: u16| i * 360 / edges).collect()
}

